  KEY `programas_diarios_detalle_camion_id_foreign` (`camion_id`),
  KEY `programas_diarios_detalle_tipo_retiro_id_foreign` (`tipo_retiro_id`),
  KEY `programas_diarios_detalle_producto_id_foreign` (`producto_id`),
  KEY `programas_diarios_detalle_especie_id_foreign` (`especie_id`),
  KEY `programas_diarios_detalle_region_operativa_id_idx` (`region_operativa_id`),
  CONSTRAINT `programas_diarios_detalle_camion_id_foreign` FOREIGN KEY (`camion_id`) REFERENCES `camiones` (`id`) ON UPDATE CASCADE,
