--
-- Table structure for table `retiros_historial`
--

DROP TABLE IF EXISTS `retiros_historial`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `retiros_historial` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `retiro_id` bigint(20) unsigned NOT NULL,
  `fecha_retiro` datetime NOT NULL,
  `tipo_retiro_id` bigint(20) unsigned NOT NULL,
  `kilogramos_estimados` int(11) NOT NULL,
  `requiere_reposicion` tinyint(1) NOT NULL DEFAULT 0,
  `cantidad_bins` int(10) unsigned DEFAULT NULL,
  `estado_id` bigint(20) unsigned DEFAULT NULL,
  `activo` tinyint(1) NOT NULL DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `usuario_id` bigint(20) unsigned NOT NULL,
  `motivo_cambio` text DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `retiros_historial_tipo_retiro_id_foreign` (`tipo_retiro_id`),
  KEY `retiros_historial_estado_id_foreign` (`estado_id`),
  KEY `retiros_historial_usuario_id_foreign` (`usuario_id`),
  KEY `retiros_historial_retiro_id_index` (`retiro_id`),
  CONSTRAINT `retiros_historial_estado_id_foreign` FOREIGN KEY (`estado_id`) REFERENCES `catalogos` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `retiros_historial_retiro_id_foreign` FOREIGN KEY (`retiro_id`) REFERENCES `retiros` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `retiros_historial_tipo_retiro_id_foreign` FOREIGN KEY (`tipo_retiro_id`) REFERENCES `catalogos` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `retiros_historial_usuario_id_foreign` FOREIGN KEY (`usuario_id`) REFERENCES `users` (`id`) ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=9717 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

