--
-- Table structure for table `sucursales`
--

DROP TABLE IF EXISTS `sucursales`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sucursales` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `zona_id` bigint(20) unsigned NOT NULL,
  `nombre_sucursal` varchar(255) NOT NULL,
  `codigo_siep` int(11) DEFAULT NULL,
  `tipo_sucursal_id` bigint(20) unsigned NOT NULL,
  `comuna_id` bigint(20) unsigned NOT NULL,
  `telefono` varchar(255) DEFAULT NULL,
  `email` varchar(255) DEFAULT NULL,
  `km` int(11) DEFAULT NULL,
  `tiempo_estimado_viaje` decimal(5,2) DEFAULT NULL,
  `activo` tinyint(1) NOT NULL DEFAULT 1,
  `observacion_inactividad` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `sucursales_zona_id_foreign` (`zona_id`),
  KEY `sucursales_tipo_sucursal_id_foreign` (`tipo_sucursal_id`),
  KEY `sucursales_comuna_id_foreign` (`comuna_id`),
  CONSTRAINT `sucursales_comuna_id_foreign` FOREIGN KEY (`comuna_id`) REFERENCES `comunas` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `sucursales_tipo_sucursal_id_foreign` FOREIGN KEY (`tipo_sucursal_id`) REFERENCES `catalogos` (`id`),
  CONSTRAINT `sucursales_zona_id_foreign` FOREIGN KEY (`zona_id`) REFERENCES `catalogos` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=53 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

